CREATE   PROCEDURE [dbo].[TR_THONGKE_SANPHAM_GETBYDATE2]
(
	@tungay DATE,
	@denngay DATE
)
AS
BEGIN
	--DECLARE @tungay DATE = '2025-01-17';
	--DECLARE @denngay DATE = '2025-01-17'

	SELECT A.madonhang, B.hehang, A.masp1 AS masp, B.tensp, 
		metvuong = SUM(CASE WHEN A.mact = '000' THEN B.m2_tc * A.soluong ELSE (A.rong*A.dai*A.soluong)/1000000 END), 
		metkhoi = SUM(CASE WHEN A.mact = '000' THEN B.m3_tc * A.soluong ELSE A.sokhoi END),
		A.ngaythang, D.n_op AS tencongdoan
	INTO #THONGKESANPHAM
	FROM tr_trangthai_sanxuat A
		INNER JOIN tr_sanpham B ON A.masp1 = B.masp
		INNER JOIN trtb_m_location C ON A.congdoan = C.c_location
		INNER JOIN trtb_m_op D ON C.c_op = D.c_op
	WHERE A.ngaythang BETWEEN @tungay AND @denngay
		AND D.department IN ('SON', 'DONGGOI')
		AND A.congdoan LIKE '%-PROD'
	GROUP BY A.ngaythang, A.madonhang, B.hehang, A.masp1, B.tensp, D.n_op

	DECLARE @HtmlRow TABLE 
	(
		stt int IDENTITY(1,1),
		htmlString nvarchar(max)
	)

	DECLARE @html nvarchar(max);
	IF EXISTS (SELECT 1 FROM #THONGKESANPHAM)
	BEGIN
		SET @html = N'<h2>BẢNG CHI TIẾT</h2>'
		SET @html = @html + char(13) + char(10) + N'<table border=''1'' cellSpacing=''0'' cellPadding=''2'' style=''width: 1300px; BACKGROUND-COLOR: #ffffff; POSITION: relative; EMPTY-CELLS: show;''>';
		SET @html = @html + char(13) + char(10) + N'<tbody>';

		-- HEADER
		SET @html = @html + char(13) + char(10) + N'<tr>';
		SET @html = @html + char(13) + char(10) + N'<th>Mã đơn hàng</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Hệ hàng</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Mã sản phẩm</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Tên sản phẩm</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Ngày nhập</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Công đoạn</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Mét vuông</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Mét khối</th>';
		SET @html = @html + char(13) + char(10) + N'</tr>';

		INSERT INTO @HtmlRow(htmlString) VALUES (@html);

		DECLARE @MADONHANG nvarchar(200), @hehang nvarchar(200), @MASP nvarchar(200), @tensp nvarchar(max), @NGAYNHAP date, @congdoan nvarchar(200); 
		DECLARE @ID INT = 0, @metvuong float = 0, @metkhoi float = 0;
		DECLARE CUR CURSOR LOCAL FOR
			SELECT GROUPING_ID(A.ngaythang, A.madonhang, A.hehang, A.masp, A.tensp, A.tencongdoan) AS ID,
				madonhang, hehang, masp, tensp, ngaythang, tencongdoan, 
				metvuong = SUM(metvuong), 
				metkhoi = SUM(metkhoi)
			FROM #THONGKESANPHAM A
			GROUP BY ROLLUP(A.ngaythang, A.madonhang, A.hehang, A.masp, A.tensp, A.tencongdoan)
			HAVING GROUPING_ID(A.ngaythang, A.madonhang, A.hehang, A.masp, A.tensp, A.tencongdoan) IN (0, 15)
		OPEN CUR
		FETCH NEXT FROM CUR INTO @ID, @MADONHANG, @hehang, @MASP, @tensp, @NGAYNHAP, @congdoan, @metvuong, @metkhoi
		WHILE @@FETCH_STATUS = 0
		BEGIN
			DECLARE @row nvarchar(max) = '';
			IF @id = 15
			BEGIN
				SET @row = @row + char(13) + char(10) + N'<tr style=''font-weight: bold;background-color: #BFBFBF''>';
				SET @row = @row + char(13) + char(10) + N'<td colSpan=''6''>Đơn hàng: ' + @MADONHANG + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + FORMAT(@metvuong, '#,0.##') + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + FORMAT(@metkhoi, '#,0.##') + '</td>';
				SET @row = @row + char(13) + char(10) + N'</tr>';
			END
			ELSE
			BEGIN
				SET @row = @row + char(13) + char(10) + N'<tr>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 150px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + @MADONHANG + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 150px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + @hehang + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 200px; VERTICAL-ALIGN: middle; TEXT-ALIGN: left;''>' + @MASP + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 300px; VERTICAL-ALIGN: middle; TEXT-ALIGN: left;''>' + @tensp + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + FORMAT(@NGAYNHAP, 'dd/MM/yyyy') + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + @congdoan + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@metvuong = 0, '&nbsp;', FORMAT(@metvuong, '#,0.##')) + '</td>';
				SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@metkhoi = 0, '&nbsp;', FORMAT(@metkhoi, '#,0.##')) + '</td>';
				SET @row = @row + char(13) + char(10) + N'</tr>';
			END

			INSERT INTO @HtmlRow(htmlString) VALUES (@row);
			FETCH NEXT FROM CUR INTO @ID, @MADONHANG, @hehang, @MASP, @tensp, @NGAYNHAP, @congdoan, @metvuong, @metkhoi
		END
		CLOSE CUR;
		DEALLOCATE CUR;

		SET @html = '';
		SET @html = @html + char(13) + char(10) + N'</tbody>';
		SET @html = @html + char(13) + char(10) + N'</table>';

		INSERT INTO @HtmlRow(htmlString) VALUES (@html);
	END
	
	SELECT stt, htmlString FROM @HtmlRow ORDER BY stt
	DROP TABLE #THONGKESANPHAM;

